# rolling_average_trend.py
# Compute 4-week rolling average of weekly incident counts
from collections import defaultdict
from datetime import datetime, timedelta
from typing import List
from dataclasses import dataclass


@dataclass
class Incident:
    created_at: datetime
    severity: str


def to_iso_week(dt: datetime) -> str:
    iso = dt.isocalendar()
    return f'{iso.year}-W{iso.week:02d}'


def weekly_counts(incidents: List[Incident]) -> dict:
    counts = defaultdict(int)
    for inc in incidents:
        counts[to_iso_week(inc.created_at)] += 1
    return dict(sorted(counts.items()))


def rolling_average(weekly: dict, window: int = 4) -> List[dict]:
    weeks = list(weekly.keys())
    counts = list(weekly.values())
    result = []
    for i, week in enumerate(weeks):
        if i < window - 1:
            avg = None
        else:
            avg = round(sum(counts[i - window + 1:i + 1]) / window, 1)
        result.append({'week': week, 'count': counts[i], 'rolling_avg': avg})
    return result


if __name__ == '__main__':
    import json
    def dt(s): return datetime.fromisoformat(s)
    # Synthetic 10-week dataset
    raw = [
        Incident(dt('2026-05-01'), 'SEV-2'), Incident(dt('2026-05-03'), 'SEV-3'),
        Incident(dt('2026-05-08'), 'SEV-1'), Incident(dt('2026-05-09'), 'SEV-2'),
        Incident(dt('2026-05-10'), 'SEV-3'), Incident(dt('2026-05-15'), 'SEV-3'),
        Incident(dt('2026-05-22'), 'SEV-2'), Incident(dt('2026-05-29'), 'SEV-3'),
        Incident(dt('2026-06-05'), 'SEV-3'), Incident(dt('2026-06-05'), 'SEV-3'),
        Incident(dt('2026-06-12'), 'SEV-3'),
    ]
    wc = weekly_counts(raw)
    trend = rolling_average(wc)
    for row in trend:
        avg_str = f"{row['rolling_avg']:.1f}" if row['rolling_avg'] is not None else 'N/A'
        print(f"{row['week']}: {row['count']:3d} incidents | 4-wk avg: {avg_str}")
